import{_ as e,o as a,c as o,ai as r}from"./chunks/framework.DMjte4z8.js";const p=JSON.parse('{"title":"变量是什么？触发器变量零基础入门","description":"","frontmatter":{"title":"变量是什么？触发器变量零基础入门","category":"triggers","updated":"2026-04-28T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://juejin.cn/post/7438849833488023593"]},"headers":[],"relativePath":"triggers/变量是什么触发器变量零基础入门.md","filePath":"triggers/变量是什么触发器变量零基础入门.md","lastUpdated":1777383225000}'),i={name:"triggers/变量是什么触发器变量零基础入门.md"};function l(s,t,n,u,_,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="变量是什么-触发器变量零基础入门" tabindex="-1">变量是什么？触发器变量零基础入门 <a class="header-anchor" href="#变量是什么-触发器变量零基础入门" aria-label="Permalink to “变量是什么？触发器变量零基础入门”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>想象一下，你在玩 RPG 游戏时，角色获得了一把武器。游戏需要记住这把武器的名字、攻击力、等级等信息，否则下次显示时就会&quot;忘记&quot;这把武器。这个<strong>&quot;记住信息&quot;</strong>的工作，就是<strong>变量（Variable）</strong>的核心职责。[^1]</p><p><strong>变量是什么？</strong> 简单来说，变量就是一个有名字的&quot;容器&quot;——你可以往里面存放数据（数字、文字、甚至是游戏中的单位），需要时再通过名字把它取出来使用。</p><h3 id="为什么触发器需要变量" tabindex="-1">为什么触发器需要变量？ <a class="header-anchor" href="#为什么触发器需要变量" aria-label="Permalink to “为什么触发器需要变量？”">​</a></h3><p>触发器（Trigger）是魔兽争霸 III 编辑器中&quot;让游戏动起来&quot;的核心工具。你可以把它理解为一段<strong>自动执行的指令清单</strong>：当某个事件发生（比如玩家点击了按钮），触发器就开始工作。[^1]</p><p>但触发器在工作过程中，经常需要<strong>保存临时数据</strong>：</p><ul><li>记录哪个玩家获得了奖励</li><li>统计场上还有多少敌人存活</li><li>记住玩家上一次选择了什么选项</li></ul><p>这些&quot;记住&quot;的操作，都离不开变量。没有变量，触发器就像金鱼一样——说完就忘，无法处理复杂一点的逻辑。</p><blockquote><p><strong>💡 新手提示</strong>：可以把变量想象成你的&quot;记事本&quot;。游戏运行时需要记录的各种信息，都写在&quot;记事本&quot;的各个页面上——每一页就是一个变量，页面标题就是变量名。</p></blockquote><h3 id="本节你能学到什么" tabindex="-1">本节你能学到什么 <a class="header-anchor" href="#本节你能学到什么" aria-label="Permalink to “本节你能学到什么”">​</a></h3><p>学完本节，你将理解：</p><ul><li>变量到底是什么（用生活比喻来理解）</li><li>变量能存放哪些类型的数据</li><li>为什么触发器离不开变量</li></ul><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手会混淆&quot;变量的名字&quot;和&quot;变量里存放的值&quot;。比如变量名叫&quot;玩家金币&quot;，里面存的可能是 <code>500</code>。记住：名字是标签，值是实际内容。</p></blockquote><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://juejin.cn/post/7438849833488023593" target="_blank" rel="noreferrer">【Y3编辑器】入门级的触发器教学：基础概念一览</a> — accessed 2026-04-28</p>',16)])])}const h=e(i,[["render",l]]);export{p as __pageData,h as default};
